"use strict";(globalThis.webpackChunkratel_docs=globalThis.webpackChunkratel_docs||[]).push([[292],{5550(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"docsSidebar":[{"type":"category","label":"About Ratel","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/dev/intro/glossary","label":"Glossary","docId":"intro/glossary","unlisted":false}],"href":"/dev/"},{"type":"link","href":"/dev/getting-started","label":"Getting Started","docId":"getting-started","unlisted":false},{"type":"link","href":"/dev/ai-connect","label":"Connect AI","docId":"ai-connect","unlisted":false},{"type":"link","href":"/dev/teams","label":"Create a Team","docId":"teams","unlisted":false},{"type":"link","href":"/dev/posts","label":"Posts","docId":"posts","unlisted":false},{"type":"category","label":"Spaces","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/dev/spaces/apps","label":"Space Apps (Host Tools)","docId":"spaces/apps","unlisted":false},{"type":"link","href":"/dev/spaces/actions","label":"Space Actions","docId":"spaces/actions","unlisted":false},{"type":"link","href":"/dev/spaces/dashboard","label":"Space Dashboard (Host)","docId":"spaces/dashboard","unlisted":false},{"type":"link","href":"/dev/spaces/host-actions","label":"Host Actions (Editors)","docId":"spaces/host-actions","unlisted":false},{"type":"link","href":"/dev/spaces/reports","label":"Reports (Host)","docId":"spaces/reports","unlisted":false}],"href":"/dev/spaces"},{"type":"link","href":"/dev/profile","label":"Profile","docId":"profile","unlisted":false},{"type":"link","href":"/dev/settings","label":"Settings","docId":"settings","unlisted":false},{"type":"link","href":"/dev/credentials","label":"Credentials","docId":"credentials","unlisted":false},{"type":"link","href":"/dev/my-essence","label":"My Essence","docId":"my-essence","unlisted":false},{"type":"link","href":"/dev/essence","label":"Essence Sources","docId":"essence","unlisted":false},{"type":"link","href":"/dev/rewards","label":"Rewards","docId":"rewards","unlisted":false},{"type":"link","href":"/dev/membership","label":"Membership","docId":"membership","unlisted":false},{"type":"link","href":"/dev/sub-teams","label":"Sub-teams","docId":"sub-teams","unlisted":false},{"type":"link","href":"/dev/team-settings","label":"Team Settings","docId":"team-settings","unlisted":false}]},"docs":{"ai-connect":{"id":"ai-connect","title":"Connect AI","description":"Ratel exposes a single MCP endpoint per user. Plug it into the AI client you already use, and your assistant gains access to your Essence \u2014 and any Essence Houses you subscribe to \u2014 as a first-class tool.","sidebar":"docsSidebar"},"credentials":{"id":"credentials","title":"Credentials","description":"Your Credentials page is where the things you\'ve proven about yourself live \u2014 your decentralized identifier (DID), the verifiable claims attached to it, and the cryptographic proof that backs them. Think of it as a privacy-preserving wallet of identity attributes you can selectively disclose to Spaces, Teams, and external verifiers.","sidebar":"docsSidebar"},"essence":{"id":"essence","title":"Essence Sources","description":"Your Essence has a control panel \u2014 one page where you can see every input feeding it, search across them, and clean out anything you no longer want. It lives at:","sidebar":"docsSidebar"},"getting-started":{"id":"getting-started","title":"Getting Started","description":"Welcome to Ratel \u2014 the Human Essence Platform. This chapter walks you through your first day: signing in, setting up your profile, connecting external accounts, and finding your way around.","sidebar":"docsSidebar"},"intro/glossary":{"id":"intro/glossary","title":"Glossary","description":"Quick definitions for every Ratel term you\'ll meet in these docs. Features marked (Coming soon) are on the roadmap \u2014 the underlying primitive may already exist, but the user-facing flow is still being built.","sidebar":"docsSidebar"},"intro/index":{"id":"intro/index","title":"About Ratel","description":"Ratel is a Human Essence Platform. It\'s a place where the thoughts, insights, and activities of real people are captured, embedded, and turned into a personal asset you can use, share, and monetize. Every post you write, every space you join, every vote, comment, and discussion you take part in becomes part of your Essence \u2014 a personal knowledge base that grows as you participate.","sidebar":"docsSidebar"},"membership":{"id":"membership","title":"Membership","description":"Membership is Ratel\'s tier system for hosts and power users. Anyone can sign up for free and use the platform; paid tiers unlock monthly Credits you can spend on reward Spaces, plus a creator badge and (at higher tiers) raw participant data access.","sidebar":"docsSidebar"},"my-essence":{"id":"my-essence","title":"My Essence","description":"Your Essence isn\'t an abstract concept \u2014 it\'s a real surface in the app, with two dedicated pages where you see what you\'ve built and what it earns you. My AI at /my-ai is where you connect Ratel to your AI assistant. Character at /me/character is where your activity becomes a level, skill points, and stat boosts you can spend.","sidebar":"docsSidebar"},"posts":{"id":"posts","title":"Posts","description":"Why posts matter","sidebar":"docsSidebar"},"profile":{"id":"profile","title":"Profile","description":"Your profile is your public corner of Ratel \u2014 the page anyone gets when they click your name or paste your handle into a browser. It lives at:","sidebar":"docsSidebar"},"rewards":{"id":"rewards","title":"Rewards","description":"Every Space you participate in, every post you publish, every comment that earns engagement \u2014 these accumulate as rewards in your account. The Rewards page is where you see what you\'ve earned, what\'s still in motion, and what\'s ready to claim.","sidebar":"docsSidebar"},"settings":{"id":"settings","title":"Settings","description":"This is the single place to change everything about your account \u2014 how you appear, how you sign in, what plan you\'re on, and how an AI agent connects to your Ratel data.","sidebar":"docsSidebar"},"spaces/actions":{"id":"spaces/actions","title":"Space Actions","description":"If Apps are the host\'s toolkit, Actions are the participant\'s quest board. Each Action is a single thing the host wants you to do \u2014 vote on something, weigh in on a discussion, answer a quiz, follow a few accounts, RSVP to a meet \u2014 and finishing it earns you a share of the Space\'s rewards while feeding your Essence with structured signal about what you think.","sidebar":"docsSidebar"},"spaces/apps":{"id":"spaces/apps","title":"Space Apps (Host Tools)","description":"If you\'re the host of a Space, Apps are the building blocks you plug in to shape it. Each App handles one job \u2014 publishing info, sharing files, asking participants to vote, generating an AI-assisted report, distributing rewards \u2014 and the App you don\'t need today, you simply leave out.","sidebar":"docsSidebar"},"spaces/dashboard":{"id":"spaces/dashboard","title":"Space Dashboard (Host)","description":"The Dashboard is the host\'s \\"how is my Space doing today\\" view \u2014 a single screen of stat cards and a participant ranking, refreshed live as people engage. It lives at:","sidebar":"docsSidebar"},"spaces/host-actions":{"id":"spaces/host-actions","title":"Host Actions (Editors)","description":"This chapter is the host-side companion to Space Actions. The participant chapter explains what an Action looks like to someone who shows up to engage; this one walks you, the host, through creating and editing each Action type.","sidebar":"docsSidebar"},"spaces/index":{"id":"spaces/index","title":"Spaces","description":"A Space is the arena where Ratel activity happens. Discussions, polls, quizzes, follow quests, scheduled meets \u2014 everything that turns a community into a measurable conversation lives inside a Space. From a Space, hosts shape what participants see, and participants accumulate Essence as they engage.","sidebar":"docsSidebar"},"spaces/reports":{"id":"spaces/reports","title":"Reports (Host)","description":"A Report is the host\'s published synthesis of what happened in their Space \u2014 what participants thought, where they agreed, where they didn\'t, what stood out. Ratel ships two report surfaces that work together:","sidebar":"docsSidebar"},"sub-teams":{"id":"sub-teams","title":"Sub-teams","description":"Sub-teams are how a parent Team formally recognizes another Team as part of its umbrella \u2014 a chapter, a working group, a partner cell \u2014 without absorbing it. Each side keeps its own posts, members, treasury, and Spaces, but the relationship is an on-platform link with rules, documents, announcements, and a public registry of who belongs to whom.","sidebar":"docsSidebar"},"team-settings":{"id":"team-settings","title":"Team Settings","description":"Team Settings is where a Team\'s admins manage the Team itself \u2014 its public identity, its members and roles, the subscription paying for its monthly Credits, and (if it comes to it) the deletion flow. This is the administrator\'s view of a Team; for the public profile and feed, see the Create a Team chapter.","sidebar":"docsSidebar"},"teams":{"id":"teams","title":"Create a Team","description":"Why teams?","sidebar":"docsSidebar"}}}}')}}]);